		m1=0;
		m2=0;
		m3=0;
		m4=0;
		m5=0;
		m6=0;
		m7=0;
		this.cohete.visible=false;
		//-----------------
		var _this = this;
		
		// --- CONFIGURACIÓN ---
		var radioEvasion = 80;   
		var fuerzaEvasion = 0.8; 
		
		// Tu arreglo original
		var mundos = [
			_this.mundo1, 
			_this.mundo2, 
			_this.mundo3, 
			_this.mundo4, 
			_this.mundo5, 
			_this.mundo6, 
		];
		
		if (!this.juegoActivo) {
			createjs.Ticker.addEventListener("tick", fl_LogicaGeneral);
			this.juegoActivo = true;
		}
		
		function fl_LogicaGeneral() {
			// 1. OBTENER ESCALA (Crucial para la web)
			var scaleX = stage.scaleX || 1;
			var scaleY = stage.scaleY || 1;
			
			var mouseX = stage.mouseX / scaleX;
			var mouseY = stage.mouseY / scaleY;
		
			// 2. VERIFICAR QUE EL CANVAS TENGA TAMAÑO
			// Si el ancho es 0, salimos de la función para no mover nada
			if (canvas.width <= 0) return;
		
			mundos.forEach(function(mundo) {
				if (!mundo) return;
		
				// CALCULAR DISTANCIA
				var dx = mundo.x - mouseX;
				var dy = mundo.y - mouseY;
				var distancia = Math.sqrt(dx * dx + dy * dy);
		
				// LÓGICA DE EVASIÓN
				if (distancia < radioEvasion && distancia > 0) {
					var angulo = Math.atan2(dy, dx);
					var velocidad = (radioEvasion - distancia) * fuerzaEvasion;
		
					mundo.x += Math.cos(angulo) * velocidad;
					mundo.y += Math.sin(angulo) * velocidad;
				}
		
				// LÓGICA DE CONTACTO (HitTest)
				// Usamos las coordenadas globales del stage para el hitTest
				var localPoint = mundo.globalToLocal(stage.mouseX, stage.mouseY);
				if (mundo.hitTest(localPoint.x, localPoint.y)) {
					fl_Teletransportar(mundo);
				}
				
				// LÓGICA DE BORDES (Solo si el objeto se movió)
				fl_LimitarBordes(mundo);
			});
		}
		
		function fl_Teletransportar(objetivo) {
			var scaleX = stage.scaleX || 1;
			var scaleY = stage.scaleY || 1;
			var anchoCanvas = canvas.width / scaleX;
			var altoCanvas = canvas.height / scaleY;
			var margen = 60;
		
			objetivo.x = Math.random() * (anchoCanvas - margen * 2) + margen;
			objetivo.y = Math.random() * (altoCanvas - margen * 2) + margen;
		}
		
		function fl_LimitarBordes(objetivo) {
			var scaleX = stage.scaleX || 1;
			var scaleY = stage.scaleY || 1;
			var anchoCanvas = canvas.width / scaleX;
			var altoCanvas = canvas.height / scaleY;
			var m = 20; 
		
			// Si las dimensiones son válidas, aplicamos límites
			if (anchoCanvas > 100) { 
				if (objetivo.x < m) objetivo.x = m;
				if (objetivo.x > anchoCanvas - m) objetivo.x = anchoCanvas - m;
				if (objetivo.y < m) objetivo.y = m;
				if (objetivo.y > altoCanvas - m) objetivo.y = altoCanvas - m;
			}
		}
		
